code = """import json, re, math, pandas as pd

def load_result(x):
    if isinstance(x, str) and x.endswith('.json'):
        with open(x, 'r') as f:
            return json.load(f)
    return x

clin = load_result(var_call_hJbsa8qNRaDIiNaH1j6r7Nnu)
expr = load_result(var_call_a8hrPWDaOIL5lMDOaVNSgv48)

clin_df = pd.DataFrame(clin)
expr_df = pd.DataFrame(expr)

# normalize column names
clin_df.columns = [c.lower() for c in clin_df.columns]
expr_df.columns = [c.lower() for c in expr_df.columns]

# extract TCGA barcode from Patient_description text
pat = re.compile(r'(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})')
clin_df['participantbarcode_extracted'] = clin_df['participantbarcode'].astype(str).apply(lambda s: (pat.search(s).group(1) if pat.search(s) else None))
clin_df = clin_df.dropna(subset=['participantbarcode_extracted','histology'])

# ensure histology not in square brackets (already filtered but double-check)
clin_df = clin_df[~clin_df['histology'].astype(str).str.match(r'^\[.*\]$')]

expr_df['normalized_count'] = pd.to_numeric(expr_df['normalized_count'], errors='coerce')
expr_df = expr_df.dropna(subset=['participantbarcode','normalized_count'])

# compute log10(normalized_count+1)
expr_df['log10_expr'] = (expr_df['normalized_count'] + 1.0).apply(lambda v: math.log10(v) if v>=0 else None)
expr_df = expr_df.dropna(subset=['log10_expr'])

# average per participant (in case multiple samples/aliquots)
expr_pt = expr_df.groupby('participantbarcode', as_index=False)['log10_expr'].mean()

merged = clin_df.merge(expr_pt, left_on='participantbarcode_extracted', right_on='participantbarcode', how='inner')

res = merged.groupby('histology', as_index=False).agg(n_patients=('participantbarcode_extracted','nunique'), avg_log10_igf2=('log10_expr','mean'))
res = res.sort_values('histology')

# format avg to 4 decimals
out_lines = []
for _, row in res.iterrows():
    out_lines.append(f"{row['histology']}: {row['avg_log10_igf2']:.4f} (n={int(row['n_patients'])})")
answer = "\n".join(out_lines)

print('__RESULT__:')
print(json.dumps(answer))"""

